1911	async function runBatchSync(kind) {
1912	  const picks = $$(`.mx-pick[data-mx-kind="${kind}"]:checked`).map((c) => ({
1913	    name: c.dataset.mxName,
1914	    sourceId: undefined,
1915	    baseTool: c.dataset.mxBase || undefined,
1916	  }));
1917	  const prog = $('#' + kind + '-mx-progress');
1918	  const out = $('#' + kind + '-mx-batch-result');
1919	  if (!picks.length) { if (prog) prog.textContent = '선택된 항목이 없습니다.'; if (out) out.innerHTML = ''; return; }
1920	  const btn = $('#' + kind + '-mx-batch-sync');
1921	  if (btn) btn.disabled = true;
1922	  const results = [];
1923	  let done = 0, ok = 0, same = 0, fail = 0, piSkip = 0;
1924	  for (const p of picks) {
1925	    if (prog) prog.textContent = `${done + 1}/${picks.length} 처리 중…`;
1926	    try {
1927	      const res = await fetch('/sync/apply', {
1928	        method: 'POST', headers: { 'Content-Type': 'application/json' },
1929	        body: JSON.stringify({ kind, name: p.name, baseTool: p.baseTool, sourceId: p.sourceId }),
1930	      });
1931	      if (res.status === 409) {
1932	        // PI 게이트 — 이 항목은 건너뛰고 계속(모달 열지 않음). 개별 [동기화]에서 처리 안내.
1933	        piSkip++;
1934	        results.push({ name: p.name, status: 'pi', msg: '민감정보 감지 — 건너뜀(개별 동기화에서 처리하세요)' });
1935	      } else if (!res.ok) {
1936	        fail++;
1937	        results.push({ name: p.name, status: 'error', msg: await errMsg(res) });
1938	      } else {
1939	        const r = await res.json();
1940	        if (r.error) { fail++; results.push({ name: p.name, status: 'error', msg: r.error }); }
1941	        else {
1942	          const pushed = (r.results || []).filter((x) => x.action === 'pushed').length;
1943	          const sk = (r.results || []).filter((x) => x.action === 'skipped_same').length;
1944	          const errs = (r.results || []).filter((x) => x.action === 'error').length;
1945	          if (errs) fail++; else ok++;
1946	          if (pushed === 0 && sk > 0 && errs === 0) { same++; }
1947	          results.push({ name: p.name, status: errs ? 'partial' : 'ok', msg: `내보냄 ${pushed} · 동일 ${sk}${errs ? ` · 오류 ${errs}` : ''}` });
1948	        }
1949	      }
1950	    } catch (e) {
1951	      fail++;
1952	      results.push({ name: p.name, status: 'error', msg: e.message });
1953	    }
1954	    done++;
1955	  }
1956	  if (btn) btn.disabled = false;
1957	  if (prog) prog.textContent = `완료 ${done}/${picks.length}`;
1958	  renderBatchResult(out, results, { ok, same, fail, piSkip });
1959	  toast(`동기화 ${ok}건 · 건너뜀 ${piSkip}건 · 실패 ${fail}건`);
1960	  // 목록 새로고침(상태 변화 반영) + 마지막 동기화 시각.
