  setCount(kind === 'skill' ? 'skills' : 'agents', (m.rows || []).length);
  // 상태 필터 기본값: 주의 필요(=drift+partial). 0건이면 자동으로 전체로 폴백(UX-E2 ②).
  const attention = (m.counts.drift || 0) + (m.counts.partial || 0);
  if (st.filter === 'attention' && attention === 0) st.filter = 'all';
  // 자동 발견 배너(첫 로드에 프로젝트를 새로 등록했을 때만).
  const scan = $('#' + kind + '-mx-scan');
  if (scan) {
    if (m.autoScan && m.autoScan.adopted > 0) {
