      scan.innerHTML = `<span class="mxb-ic">🔎</span><span>프로젝트 ${m.autoScan.adopted}개를 자동으로 찾았습니다.</span>`;
    } else { scan.hidden = true; scan.innerHTML = ''; }
  }
  // F4(skill): 선택된 폴더가 더 이상 존재하지 않으면(스캔·해제 등) [전체]로 되돌린다.
  if (kind === 'skill') {
    if (st.folder && !(m.rows || []).some((r) => r.scope === st.folder)) st.folder = null;
    renderFolderList();
