  return 8;
}

// ── F4: 좌측 폴더 리스트 (scope 기준 클라이언트 그룹핑) ──
// rows를 scope로 묶어 폴더 목록을 만든다. scope는 서버에서 'global' 또는 프로젝트 루트 절대경로.
// 반환: [{scope, label, folder, count, unsynced}] — 전역 먼저, 그다음 폴더명(경로)순.
// (rows는 이미 서버가 전역→프로젝트 경로순으로 정렬해 내려주지만, 여기서 명시적으로 재정렬한다.)
function skillFolderGroups() {
  const rows = (mxState.skill.data && mxState.skill.data.rows) || [];
  const map = new Map(); // scope → {scope, label, folder, count, unsynced}
  for (const r of rows) {
    let g = map.get(r.scope);
    if (!g) {
      g = {
        scope: r.scope,
        label: r.scope === 'global' ? '전역(~)' : baseName(r.scope),
        folder: r.scope === 'global' ? '전역(~)' : r.scope, // 검색 대상 문자열
        count: 0,
        unsynced: 0,
      };
      map.set(r.scope, g);
    }
    g.count += 1;
    if (r.syncState !== 'synced') g.unsynced += 1;
  }
  const groups = [...map.values()];
  groups.sort((a, b) => {
    if (a.scope === 'global') return -1;
    if (b.scope === 'global') return 1;
    return a.scope < b.scope ? -1 : a.scope > b.scope ? 1 : 0;
  });
  return groups;
}

// 폴더 리스트 렌더: [전체] + 폴더 항목(미동기화 배지). folderQ(이름 부분일치)로 거른다.
function renderFolderList() {
  const box = $('#skill-folder-list');
  if (!box) return;
  const st = mxState.skill;
  const groups = skillFolderGroups();
  const q = (st.folderQ || '').trim().toLowerCase();
  const filtered = q
    ? groups.filter((g) => g.label.toLowerCase().includes(q) || g.folder.toLowerCase().includes(q))
    : groups;
  const totalUnsynced = groups.reduce((a, g) => a + g.unsynced, 0);
  const totalCount = groups.reduce((a, g) => a + g.count, 0);

  // [전체] 항목은 검색어와 무관하게 항상 맨 위에 둔다(전체 스킬로 되돌아가는 진입점).
  const allItem = folderItemHtml({
    scope: null, label: '전체', count: totalCount, unsynced: totalUnsynced,
  }, st.folder === null);
  const items = filtered.map((g) => folderItemHtml(g, st.folder === g.scope)).join('');
  const emptyHint = (!filtered.length && q)
    ? '<div class="mdf-empty">일치하는 폴더가 없습니다</div>'
    : '';
  box.innerHTML = allItem + items + emptyHint;
}

function folderItemHtml(g, active) {
  // 미동기화 배지: >0이면 경고 톤 개수, 0이면 은은한 "모두 맞음".
  const badge = g.unsynced > 0
    ? `<span class="mdf-badge warn">${g.unsynced}</span>`
    : `<span class="mdf-badge ok">모두 맞음</span>`;
  const scopeAttr = g.scope == null ? '' : ` title="${esc(g.scope === 'global' ? '전역 홈(~)' : g.scope)}"`;
  const ic = g.scope == null ? '🗂️' : (g.scope === 'global' ? '🏠' : '📁');
  return `<button class="mdf-item ${active ? 'active' : ''}" data-folder="${g.scope == null ? '' : esc(g.scope)}"${scopeAttr}>
    <span class="mdf-ic">${ic}</span>
    <span class="mdf-label">${esc(g.label)}</span>
    ${badge}
  </button>`;
}

// 폴더 선택 → 우측 표를 그 폴더의 스킬만 표시. null(빈 문자열)이면 [전체].
function selectFolder(scope) {
  const st = mxState.skill;
  st.folder = scope || null;
  st.page = 1;
  renderFolderList();
  applySkillScopeColumn();
  renderMatrix('skill');
}

// F4: [전체] 선택 시에만 경로 컬럼을 보여준다(폴더 선택 시 숨김 — 좌측이 대체).
function applySkillScopeColumn() {
  const tbl = $('#skill-mx-table');
  if (!tbl) return;
  tbl.classList.toggle('mx-hide-scope', mxState.skill.folder != null);
}

// 폴더 리스트 검색 입력.
function applyFolderSearch(q) {
  mxState.skill.folderQ = q;
  renderFolderList();
}

