.sync-summary ul { margin: 6px 0 0 18px; padding: 0; }
.sync-summary li { margin: 2px 0; }

/* ═══════════ F4: 스킬 마스터-디테일 (좌측 폴더 + 우측 표) — 추가만 ═══════════ */
/* ≥1024px: 2열(폴더 리스트 | 표). <1024px: 세로로 쌓임(반응형 셸 유지). */
.master-detail {
  display: grid; grid-template-columns: 264px minmax(0, 1fr); gap: 18px; align-items: start;
}
.md-detail { min-width: 0; } /* 표가 그리드 트랙을 넘어 가로 스크롤 유발하지 않게 */

/* 좌측 폴더 패널 */
.md-folders {
  background: var(--color-canvas); border: 1px solid var(--color-hairline);
  border-radius: var(--radius-lg); padding: 12px; position: sticky; top: 12px;
  display: flex; flex-direction: column; gap: 10px; max-height: calc(100vh - 120px);
}
.mdf-head {
  font-size: 11px; font-weight: 600; letter-spacing: 0.02em; text-transform: uppercase;
  color: var(--st-muted); padding: 2px 4px;
}
.mdf-search { min-width: 0; }
.mdf-search input { width: 100%; }
.mdf-list { display: flex; flex-direction: column; gap: 3px; overflow-y: auto; min-height: 0; }
.mdf-item {
  display: flex; align-items: center; gap: 9px; width: 100%; text-align: left;
  padding: 9px 11px; border-radius: 10px; border: 1px solid transparent;
  background: transparent; color: var(--color-ink); cursor: pointer;
  transition: background var(--duration-fast), border-color var(--duration-fast);
}
.mdf-item:hover { background: var(--color-canvas-parchment); }
.mdf-item.active { background: var(--color-canvas-parchment); border-color: var(--color-hairline); }
.mdf-item.active .mdf-label { font-weight: 600; }
.mdf-ic { flex: none; font-size: 14px; }
.mdf-label {
  flex: 1; min-width: 0; font-size: 13px; letter-spacing: -0.1px;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.mdf-badge {
  flex: none; font-size: 10.5px; font-weight: 600; padding: 2px 7px; border-radius: 9999px;
  font-variant-numeric: tabular-nums; line-height: 1.4;
}
.mdf-badge.warn { color: var(--st-warn); background: var(--st-warn-soft); }
.mdf-badge.ok { color: var(--st-muted); background: transparent; font-weight: 400; }
.mdf-empty { font-size: 12.5px; color: var(--st-muted); padding: 14px 6px; text-align: center; }

/* F4: 폴더 선택 시 경로 컬럼 숨김([전체]에서만 노출). th + 각 행의 td를 함께 접는다. */
.mx-table.mx-hide-scope th.mx-scope-col,
.mx-table.mx-hide-scope td.mx-scope-cell { display: none; }

/* <1024px: 반응형 셸을 깨지 않도록 폴더 패널을 위로 쌓고, 리스트는 가로로 접이(스크롤). */
@media (max-width: 1023.98px) {
  .master-detail { grid-template-columns: 1fr; gap: 14px; }
  .md-folders {
    position: static; max-height: none; flex-direction: column;
  }
  /* 좁은 화면에서는 폴더 항목을 가로 스크롤 칩 줄로(세로 목록이 화면을 다 먹지 않게). */
  .md-folders .mdf-list {
    flex-direction: row; overflow-x: auto; overflow-y: hidden; gap: 6px;
    scrollbar-width: none; -webkit-overflow-scrolling: touch;
  }
  .md-folders .mdf-list::-webkit-scrollbar { display: none; }
  .mdf-item {
    flex: none; border: 1px solid var(--color-hairline); border-radius: 9999px;
    padding: 7px 12px;
  }
  .mdf-item.active { background: var(--color-ink); border-color: var(--color-ink); }
  .mdf-item.active .mdf-label { color: #fff; }
  .mdf-item.active .mdf-badge.ok { color: rgba(255, 255, 255, 0.72); }
}

