  return JSON.stringify({ active, rows, scopeColHidden, ctx });
})()

(() => {
  // still in 전역(~) folder. Switch state filter to 'all' to see full sort order.
  const allF = Array.from(document.querySelectorAll('#skill-mx-state .filter-pill')).find(b => b.dataset.mxFilter === 'skill:all');
  allF.click();
  const rows = Array.from(document.querySelectorAll('#skill-mx-rows tr[data-mx-row]')).map(tr => tr.dataset.mxName + ' [' + (tr.querySelector('.badge')||{}).textContent.trim() + ']');
  return JSON.stringify({ rows });
})()

(() => {
  // Reset to 전체 folder
  document.querySelector('#skill-folder-list .mdf-item[data-folder=""]').click();
  // Click tag "docs" then "demo" (OR)
  const clickTag = (tag) => { const b = Array.from(document.querySelectorAll('#skills-filters .filter-pill')).find(x => x.dataset.tagFilter === tag); if(b) b.click(); return !!b; };
  const okDocs = clickTag('docs');
  const okDemo = clickTag('demo');
  const activeChips = Array.from(document.querySelectorAll('#skills-filters .filter-pill.active')).map(b=>b.textContent);
  const rows = Array.from(document.querySelectorAll('#skill-mx-rows tr[data-mx-row]')).map(tr => tr.dataset.mxName);
  const ctx = (document.querySelector('#skill-mx-context')||{}).textContent.trim().split('\n')[0];
  return JSON.stringify({ okDocs, okDemo, activeChips, rows, ctx });
})()

(() => {
