(() => {
  const md = document.querySelector('.master-detail');
  const cs = getComputedStyle(md);
  const folders = document.querySelector('.md-folders');
  const fcs = getComputedStyle(folders);
  const listDir = getComputedStyle(document.querySelector('#skill-folder-list')).flexDirection;
  return JSON.stringify({ gridCols: cs.gridTemplateColumns, foldersPosition: fcs.position, listDir });
})()

(() => {
  // Find the .master-detail base rule and the media-query override in the loaded stylesheet.
  let base=null, mq=null, hideScope=null;
  for (const ss of document.styleSheets) {
    let rules; try { rules = ss.cssRules; } catch(e){ continue; }
    for (const r of rules) {
      if (r.selectorText === '.master-detail') base = r.style.gridTemplateColumns;
      if (r.selectorText === '.mx-table.mx-hide-scope th.mx-scope-col, .mx-table.mx-hide-scope td.mx-scope-cell') hideScope = r.style.display;
      if (r.type === CSSRule.MEDIA_RULE && r.conditionText && r.conditionText.includes('1023.98px')) {
        for (const ir of r.cssRules) { if (ir.selectorText === '.master-detail') mq = ir.style.gridTemplateColumns; }
      }
    }
  }
  return JSON.stringify({ baseGrid: base, mqGrid: mq, hideScopeDisplay: hideScope });
})()

(() => {
  const hasFolderPane = !!document.querySelector('#agent-mx-rows') && !document.querySelector('section[data-panel="agents"] .md-folders');
  const rows = Array.from(document.querySelectorAll('#agent-mx-rows tr[data-mx-row]')).map(tr => tr.dataset.mxName + ' [' + (tr.querySelector('.badge')||{}).textContent.trim() + ']');
  // switch to 'all' to check drift sorting
  const allF = Array.from(document.querySelectorAll('#agent-mx-state .filter-pill')).find(b => b.dataset.mxFilter === 'agent:all');
  if (allF) allF.click();
  const rowsAll = Array.from(document.querySelectorAll('#agent-mx-rows tr[data-mx-row]')).map(tr => tr.dataset.mxName + ' [' + (tr.querySelector('.badge')||{}).textContent.trim() + ']');
  // agent table scope column present?
  const scopeCells = document.querySelectorAll('#agent-mx-rows .mx-scope-cell').length;
  const scopeVisible = scopeCells ? getComputedStyle(document.querySelector('#agent-mx-rows .mx-scope-cell')).display !== 'none' : null;
  return JSON.stringify({ hasFolderPane, rows, rowsAll, scopeCells, scopeVisible });
})()

(() => {
  // agent tag chips exist (shared loadTags). Click a tag to ensure OR filter works cross-view.
  const chips = document.querySelectorAll('#agents-filters .filter-pill').length;
  const errBox = document.querySelector('.load-error');
  return JSON.stringify({ agentTagChips: chips, anyLoadError: !!errBox });
})()

